/**
 * Creates a new ProcessOutputException with a custom prefix added to the message.
 * This method enhances the original exception by prepending a custom prefix
 * to the error message while preserving the original exit code and output.
 *
 * @param customPrefix The custom prefix to add to the exception message
 * @param ex The original ProcessOutputException
 * @return A new ProcessOutputException with the modified message
 */
public static ProcessOutputException withParagraph(String customPrefix, ProcessOutputException ex) {
    // Create a new message by combining the custom prefix with the original output
    // If the original output is null, use an empty string instead
    var messageSuffix = ex.getOutput() != null ? ex.getOutput() : "";
    var message = customPrefix + "\n\n" + messageSuffix;

    // Return a new exception with the combined message and the original exit code and output
    return new ProcessOutputException(message, ex.getExitCode(), ex.getOutput());
}
