/**
 * Executes a callable task with a specified ClassLoader as the context ClassLoader.
 * This method temporarily changes the current thread's context ClassLoader to the provided one,
 * executes the callable task, and then restores the original ClassLoader regardless of whether
 * the task completes normally or throws an exception.
 *
 * @param <T> The return type of the callable task
 * @param classLoader The ClassLoader to be used as the context ClassLoader during execution
 * @param callable The task to be executed with the specified ClassLoader
 * @return The result of the callable task execution
 * @throws Exception If the callable task throws an exception
 */
public static <T> T execute(ClassLoader classLoader, Callable<T> callable) throws Exception {
    // Store the current thread's context ClassLoader to restore it later
    ClassLoader old = Thread.currentThread().getContextClassLoader();
    try {
        // Set the specified ClassLoader as the current thread's context ClassLoader
        Thread.currentThread().setContextClassLoader(classLoader);
        // Execute the callable task with the new ClassLoader context
        return callable.call();
    } finally {
        // Restore the original context ClassLoader in all cases (success or exception)
        Thread.currentThread().setContextClassLoader(old);
    }
}
