/**
 * Creates an appropriate OutboundInvocation instance based on the gateway status.
 * 
 * This method determines whether to create a gateway or standard HTTP outbound invocation
 * by checking the request context attributes and application service configuration.
 * 
 * @param request The HTTP outbound request to be processed
 * @return An OutboundInvocation instance appropriate for the current gateway status
 */
private OutboundInvocation<HttpOutboundRequest> createOutlet(HttpOutboundRequest request) {
    // Determine if gateway mode should be used by checking request attributes
    // or falling back to the application service configuration
    Boolean gateway = RequestContext.getAttribute(Carrier.ATTRIBUTE_GATEWAY);
    gateway = gateway == null ? context.getApplication().getService().isGateway() : gateway;

    // Create and return either a gateway or standard HTTP outbound invocation based on the gateway flag
    return gateway ? new GatewayHttpOutboundInvocation<>(request, context) :
            new HttpOutboundInvocation<>(request, context);
}
