/**
 * Invokes a blocking request against a specific endpoint in the cluster
 * This method handles the load-balanced request execution against a Spring endpoint
 * and returns the response wrapped in a CompletionStage.
 *
 * @param request The blocking cluster request to be processed
 * @param endpoint The Spring endpoint to send the request to
 * @return A CompletionStage containing the blocking cluster response or an exception
 */
@Override
public CompletionStage<BlockingClusterResponse> invoke(BlockingClusterRequest request, SpringEndpoint endpoint) {
    try {
        // Create a load-balanced request from the original request and execute it against the endpoint instance
        LoadBalancerRequest<ClientHttpResponse> lbRequest = requestFactory.createRequest(request.getRequest(), request.getBody(), request.getExecution());
        ClientHttpResponse response = lbRequest.apply(endpoint.getInstance());
        return CompletableFuture.completedFuture(new BlockingClusterResponse(response));
    } catch (Throwable e) {
        // If any exception occurs, wrap it in a failed CompletionStage
        return Futures.future(e);
    }
}
