/**
 * Creates an ErrorEventBuilder from a throwable object with a custom message.
 * This method either retrieves a pre-existing builder associated with the throwable
 * or creates a new one with the throwable and description.
 *
 * @param msg The custom error message to be included in the event
 * @param t The throwable object that triggered the error
 * @return An ErrorEventBuilder instance configured with the throwable and message
 */
public static ErrorEventBuilder fromThrowable(String msg, Throwable t) {
    // Check if we already have a builder associated with this throwable
    // If found, remove it from the map and update its description
    if (EVENT_BASES.containsKey(t)) {
        return EVENT_BASES.remove(t).description(msg);
    }

    // Otherwise create a new builder with the throwable and a combined description
    // that includes both the provided message and the throwable's message (if available)
    return builder()
            .throwable(t)
            .description(
                    msg + (t.getMessage() != null ? "\n\n" + t.getMessage().trim() : ""));
}
