/**
 * Initialize merchant application context with the specified application ID
 * This method retrieves a merchant application from cache, validates its status,
 * and copies its properties to the local thread context.
 *
 * @param appId The merchant application ID to initialize
 * @throws ConfigNotEnableException When the merchant application is not enabled
 */
public void initMchApp(String appId) {
    // Retrieve merchant application from cache service using the provided appId
    MchApp mchApp = mchAppCacheService.get(appId);

    // Validate that the merchant application is enabled, throw exception if not
    if (!Objects.equals(mchApp.getStatus(), MchAppStatusEnum.ENABLE.getCode())){
        throw new ConfigNotEnableException("商户应用未启用");
    }

    // Copy merchant application properties to the thread-local context
    MchAppLocal mchAppInfo = PaymentContextLocal.get().getMchAppInfo();
    BeanUtil.copyProperties(mchApp, mchAppInfo);
}
