/**
 * Converts an iterator of type V to an iterator of type T using a mapping function.
 * This utility method allows for transforming elements of one iterator to another type
 * without creating intermediate collections.
 *
 * @param <V> The source iterator element type
 * @param <T> The target iterator element type
 * @param iterator The source iterator to be converted
 * @param function The mapping function to convert elements from type V to type T
 * @return A new iterator that yields elements of type T, or null if the input iterator is null
 * @throws IllegalArgumentException if the mapping function is null
 */
public static <V, T> Iterator<T> toIterator(Iterator<V> iterator, Function<V, T> function) {
    // Validate inputs: function must not be null, and return null if iterator is null
    if (function == null) {
        throw new IllegalArgumentException("function is null");
    } else if (iterator == null) {
        return null;
    }

    // Create and return a new converter iterator that applies the function to each element
    return new ConverterIterator<>(iterator, function);
}
