/**
 * Accumulates acknowledgment counts and determines when to forward them.
 * This method manages a delayed acknowledgment mechanism, accumulating ack counts
 * until they reach a threshold before forwarding them to reduce network overhead.
 *
 * @param ackCount The number of acknowledgments to accumulate
 * @return The number of acknowledgments to forward, or 0 if the threshold is not reached
 */
public int accumulateAckCount(final int ackCount) {
    // Add the incoming ack count to our accumulated total
    int delayedAckCount = this.delayedAckCount.addAndGet(ackCount);

    // Calculate how many acks we have above the minimum threshold
    int ackCountToForward = delayedAckCount - MINIMUM_DELAYED_ACK_COUNT;

    // If we've accumulated enough acks to exceed the window size,
    // reset the tracking state and forward the excess acks
    if (ackCountToForward >= LastSeenMessages.WINDOW_SIZE) {
        this.lastSeenMessages = DUMMY_LAST_SEEN_MESSAGES;
        this.delayedAckCount.set(MINIMUM_DELAYED_ACK_COUNT);
        return ackCountToForward;
    }

    // Not enough acks accumulated yet to forward
    return 0;
}
