/**
 * Reads a key file from the specified path and returns its contents as a string.
 * This method reads the entire file into memory at once, which is appropriate for
 * relatively small key files.
 *
 * @param keyPath The file path where the key is stored
 * @return The contents of the key file as a string
 * @throws IOException If an error occurs during file reading
 */
private static String readKey(String keyPath) throws IOException {
    // Open the key file and read all bytes into memory
    // This approach loads the entire file at once, which works well for typical key files
    File f = new File(keyPath);
    FileInputStream fis = new FileInputStream(f);
    DataInputStream dis = new DataInputStream(fis);
    byte[] keyBytes = new byte[(int) f.length()];
    dis.readFully(keyBytes);
    dis.close();

    // Convert the byte array to a string and return it
    return new String(keyBytes);
}
