/**
 * Retrieves the HoodieInstant commit that occurred at or before the specified time instant.
 * 
 * This method finds the last completed commit that was made at or before the given
 * timestamp. If no such commit exists, it returns null.
 * 
 * @param instant The time instant to search for commits at or before
 * @return The HoodieInstant representing the last commit at or before the specified instant,
 *         or null if no such commit exists
 */
private HoodieInstant getCommitAtInstant(Instant instant) {
  // Convert the Java time Instant to Hudi commit format, find all commits before or at
  // that time, and return the most recent one (or null if none exists)
  return getCompletedCommits()
      .findInstantsBeforeOrEquals(HudiInstantUtils.convertInstantToCommit(instant))
      .lastInstant()
      .orElse(null);
}
