/**
 * Determines if the operation is applicable to the selected entries in the file system browser.
 * This method validates whether the action can be performed on the current selection based on file types.
 *
 * @param model The open file system model containing the context
 * @param entries List of browser entries that are currently selected
 * @return true if the operation can be applied to the selected entries, false otherwise
 */
@Override
public boolean isApplicable(OpenFileSystemModel model, List<BrowserEntry> entries) {
    // Check if either:
    // 1. Exactly one directory is selected, or
    // 2. Only files (no directories) are selected
    return (entries.size() == 1
                    && entries.stream()
                            .allMatch(entry -> entry.getRawFileEntry().getKind() == FileKind.DIRECTORY))
