/**
 * Initializes the rate limiter with warmup parameters.
 * This method configures the rate limiter with warmup-specific settings,
 * calculating the necessary parameters for transitioning from a cold state
 * to a steady state over the warmup period.
 */
@Override
protected void initialize() {
    // Calculate warmup time in microseconds and threshold permits
    this.warmupMicros = option.getPositive(KEY_WARMUP_SECONDS, DEFAULT_WARMUP_SECONDS) * MICROSECOND_OF_ONE_SECOND;
    this.thresholdPermits = 0.5 * warmupMicros / permitIntervalMicros;

    // Calculate the interval for cold state using the configured cold factor
    this.coldIntervalMicros = permitIntervalMicros * option.getPositive(KEY_COLD_FACTOR, DEFAULT_COLD_FACTOR);

    // Initialize parent class parameters
    super.initialize();

    // Calculate the slope for the linear function that determines permit acquisition time
    // as the limiter transitions from cold to steady state
    this.slope = (coldIntervalMicros - permitIntervalMicros) / (maxStoredPermits - thresholdPermits);
}
