/**
 * Converts a value from Iceberg's internal representation to a Java object.
 * This method handles the conversion of ByteBuffer data to appropriate Java types
 * based on the specified Iceberg field type, with special handling for string values.
 *
 * @param fieldType The Iceberg Type of the field being converted
 * @param value The ByteBuffer containing the value to convert
 * @return The converted Java object, or null if the input value is null
 */
private Object convertFromIcebergValue(Type fieldType, ByteBuffer value) {
    // Return null if the input value is null
    if (value == null) {
      return null;
    }

    // Convert the ByteBuffer to a Java object based on the Iceberg field type
    Object convertedValue = Conversions.fromByteBuffer(fieldType, value);

    // Special handling for string values - ensure they are returned as Java Strings
    if (fieldType.typeId() == Type.TypeID.STRING) {
      return convertedValue.toString();
    }

