/**
 * Generates a unique allocation order number
 * The order number is composed of the environment identifier, allocation type marker ('A'),
 * current datetime, machine number, and a sequential counter to ensure uniqueness.
 * 
 * @return A unique allocation order number string
 */
public static String allocation() {
    // Create a unique order number by combining environment prefix, timestamp, machine ID, and an atomic counter
    StringBuilder orderNo = new StringBuilder();
    String dateStr = LocalDateTime.now().format(DatePattern.PURE_DATETIME_FORMATTER);
    long id = ATOMIC_LONG.incrementAndGet();
    orderNo.append(env).append("A").append(dateStr).append(machineNo)
