/**
 * Creates a memory segment pool for server buffer management.
 * 
 * This method initializes a LazyMemorySegmentPool with configuration parameters
 * from the provided Configuration object. The pool is sized based on the total
 * memory allocation and individual page size settings.
 *
 * @param conf The configuration containing memory allocation settings
 * @return A configured LazyMemorySegmentPool instance for server buffer management
 */
public static LazyMemorySegmentPool createServerBufferPool(Configuration conf) {
    // Calculate the pool parameters based on configuration values:
    // - Total memory allocation for the buffer pool
    // - Individual page size for memory segments
    // - Number of segments based on total size divided by page size
    long totalBytes = conf.get(ConfigOptions.SERVER_BUFFER_MEMORY_SIZE).getBytes();
    int pageSize = (int) conf.get(ConfigOptions.SERVER_BUFFER_PAGE_SIZE).getBytes();
    int segmentCount = (int) (totalBytes / pageSize);

    return new LazyMemorySegmentPool(segmentCount, pageSize, DEFAULT_WAIT_TIMEOUT_MS);
}
