/**
 * Filters inbound invocations by applying permission policies defined in the service metadata.
 * 
 * This method checks if the service has any permission policies and applies them to the current
 * invocation before allowing it to proceed through the filter chain.
 *
 * @param <T> The type of inbound request
 * @param invocation The current inbound invocation being processed
 * @param chain The filter chain to continue processing after permission check
 * @return A CompletionStage representing the asynchronous result of the invocation
 */
@Override
public <T extends InboundRequest> CompletionStage<Object> filter(InboundInvocation<T> invocation, InboundFilterChain chain) {
    // Extract permission policies from service metadata and apply them if they exist
    ServicePolicy servicePolicy = invocation.getServiceMetadata().getServicePolicy();
    List<PermissionPolicy> policies = servicePolicy == null ? null : servicePolicy.getPermissionPolicies();
    if (null != policies) {
        pass(invocation, policies);
    }

    // Continue processing the invocation through the filter chain
    return chain.filter(invocation);
}
