/**
 * Drops a Neo4j database if it exists.
 * 
 * This method establishes a session with the current database and executes
 * a write transaction to drop the specified database. The operation is only
 * performed if the database exists.
 *
 * @param database The name of the database to drop
 */
public void dropDatabase(String database) {
    // Create a session connected to the current database to execute the drop command
    Session session = driver.session(SessionConfig.forDatabase(this.database));

    // Execute a write transaction that drops the specified database if it exists
    session.writeTransaction(
        tx -> {
          tx.run(String.format("DROP DATABASE %s IF EXISTS", database));
          tx.commit();
          return null;
        });
  }
