/**
 * Completes a CompletableFuture with the result of a Callable operation.
 * This utility method executes the provided Callable and completes the future
 * with either the successful result or the exception that occurred during execution.
 *
 * @param <T> The type of result returned by the Callable and completed in the future
 * @param future The CompletableFuture to be completed
 * @param operation The Callable operation whose result will complete the future
 */
public static <T> void completeFromCallable(
            CompletableFuture<T> future, Callable<T> operation) {
    try {
        // Execute the callable operation and complete the future with its result
        future.complete(operation.call());
    } catch (Exception e) {
        // If the operation throws an exception, complete the future exceptionally
        future.completeExceptionally(e);
    }
}
