 * This filter checks if there's a local IP address available and if so,
 * filters the route target to only include endpoints that match the local IP.
 * 
 * @param <T> The type of outbound request
 * @param invocation The outbound invocation to be filtered
 * @param chain The filter chain to continue processing after this filter
 */
@Override
public <T extends OutboundRequest> void filter(OutboundInvocation<T> invocation, RouteFilterChain chain) {
    // Get the route target and attempt to filter it to prefer local endpoints
    RouteTarget target = invocation.getRouteTarget();
    String localIp = Ipv4.getLocalIp();
    if (localIp != null) {
        target.filter(endpoint -> endpoint.getHost().equals(localIp));
    }

    // Continue the filter chain processing
    chain.filter(invocation);
}
