/**
 * Applies a regular expression pattern to modify a string.
 * This method searches for occurrences of the specified regex pattern in the input string
 * and replaces all matches with the provided replacement string.
 *
 * @param data The input string to be modified
 * @param regex The regular expression pattern to search for
 * @param replaceWith The string to replace matched patterns with
 * @return The modified string after replacement, or the original string if no matches found
 */
public static String applyRegexModifier(String data, String regex, String replaceWith) {
    // Compile the regex pattern and check if there's at least one match in the data
    // If matches are found, replace all occurrences with the replacement string
    Pattern pattern = Pattern.compile(regex);
    Matcher matcher = pattern.matcher(data);
    if (matcher.find()) {
        data = data.replaceAll(regex, replaceWith);
    }
