/**
 * Retrieves a map of available plugins from the plugin directory.
 * 
 * This method scans the configured plugin path for readable directories,
 * treating each directory as a plugin. The resulting map contains plugin names
 * as keys and their corresponding directory files as values.
 *
 * @return A map where keys are plugin names and values are the plugin directory files
 */
public Map<String, File> getPlugins() {
    Map<String, File> result = new HashMap<>();

    // Find all readable directories in the plugin path
    File[] files = pluginPath.listFiles(pathname -> pathname.isDirectory() && pathname.canRead());

    // Add each directory to the result map with its name as the key
    if (files != null)
        for (File file : files) {
            result.put(file.getName(), file);
        }
    return result;
