/**
 * Converts a value from Iceberg's ByteBuffer representation to the appropriate Java object.
 * This method handles the conversion of Iceberg data types to their corresponding Java types,
 * with special handling for String values.
 *
 * @param fieldType The Iceberg Type of the field being converted
 * @param value The ByteBuffer containing the value to convert
 * @return The converted value as a Java object, or null if the input value is null
 */
private Object convertFromIcebergValue(Type fieldType, ByteBuffer value) {
    // Return null if the input value is null
    if (value == null) {
      return null;
    }

    // Use Iceberg's Conversions utility to convert the ByteBuffer to the appropriate Java type
    Object convertedValue = Conversions.fromByteBuffer(fieldType, value);

    // Special handling for STRING type - ensure it's returned as a Java String
    if (fieldType.typeId() == Type.TypeID.STRING) {
      return convertedValue.toString();
    }

    return convertedValue;
  }
