/**
 * Converts a list of source objects to a list of target objects using the provided converter function.
 * This utility method applies the conversion function to each element in the source list
 * and collects the results into a new list.
 *
 * @param <S> The type of objects in the source list
 * @param <T> The type of objects in the target list
 * @param sources The list of source objects to be converted
 * @param converter The function to convert from source type to target type
 * @return A new list containing the converted objects, or an empty list if sources or converter is null
 */
public static <S, T> List<T> convert(List<S> sources, Function<S, T> converter) {
    // Return empty list if either sources or converter is null to avoid NullPointerException
    if (sources == null || converter == null) {
        return new ArrayList<>();
    }

    // Create a result list with the same capacity as the source list for efficiency
    // and apply the converter function to each source element
    List<T> result = new ArrayList<>(sources.size());
    for (S instance : sources) {
        result.add(converter.apply(instance));
    }
    return result;
}
