/**
 * Determines if a file entry matches the specified file extensions or names.
 * This method checks if the file entry has an extension or name that matches
 * any of the predefined endings in the collection.
 *
 * @param entry The file entry to check for matching
 * @return true if the entry's extension or name matches any of the specified endings, false otherwise
 */
@Override
public boolean matches(FileSystem.FileEntry entry) {
    // Skip directories as they don't have extensions
    if (entry.getKind() == FileKind.DIRECTORY) {
        return false;
    }

    // Check if the file extension or the complete filename matches any of the specified endings
    return (entry.getExtension() != null
                    && endings.contains("." + entry.getExtension().toLowerCase(Locale.ROOT)))
            || endings.contains(entry.getName());
