/**
 * Parses a command input string for a given command source.
 * This method normalizes the input and uses the command dispatcher to parse it
 * while ensuring thread safety with a read lock.
 *
 * @param input The raw command input string to be parsed
 * @param source The command source that is executing the command
 * @return ParseResults containing the parsed command information
 */
private ParseResults<CommandSource> parse(final String input, final CommandSource source) {
    // Normalize the input string to standardize format before parsing
    final String normalizedInput = VelocityCommands.normalizeInput(input, true);

    // Acquire read lock to ensure thread-safe access to the dispatcher
    lock.readLock().lock();
    try {
      return dispatcher.parse(normalizedInput, source);
    } finally {
      // Always release the lock even if an exception occurs
      lock.readLock().unlock();
    }
  }
