/**
 * Determines the default file system location for a given namespace.
 * 
 * This method constructs a path based on the default base location and the
 * provided namespace. If the namespace is empty, it returns the default base
 * location as is. Otherwise, it appends the namespace levels to the default
 * base location to form a complete path.
 *
 * @param namespace The namespace to resolve to a file system location
 * @return The default file system location for the given namespace
 */
private String defaultNamespaceLocation(Namespace namespace) {
    // For empty namespaces, simply return the default base location
    if (namespace.isEmpty()) {
      return defaultBaseLocation;
    } else {
      // For non-empty namespaces, join the namespace levels and append to the base location
      return SLASH.join(defaultBaseLocation, SLASH.join(namespace.levels()));
    }
  }
