/**
 * Determines the operating system of the current environment.
 * This method examines the system property "os.name" and returns
 * the corresponding Local enum value for the detected operating system.
 * 
 * @return The Local enum value representing the current operating system:
 *         MACOS for macOS/Darwin systems, WINDOWS for Windows systems,
 *         or LINUX for all other systems (defaulting to Linux)
 */
static Local getLocal() {
    // Determine the operating system by checking the "os.name" system property
    // Convert to lowercase and use English locale for consistent string matching
    String osName = System.getProperty("os.name", "generic").toLowerCase(Locale.ENGLISH);

    // Check for macOS/Darwin systems
    if ((osName.contains("mac")) || (osName.contains("darwin"))) {
        return MACOS;
    } 
    // Check for Windows systems
    else if (osName.contains("win")) {
        return WINDOWS;
    } 
    // Default to Linux for all other operating systems
    else {
        return LINUX;
    }
}
