/**
 * Initializes and returns a Configuration object with default settings for the log replication system.
 * This method sets up critical configuration parameters such as replication factor,
 * maximum allowed replica lag time, and minimum required in-sync replicas.
 *
 * @return A Configuration object with predefined settings
 */
private static Configuration initConfig() {
    // Create a new Configuration instance and set the default replication factor to 3
    // which means each log will be replicated across 3 different nodes for redundancy
    Configuration conf = new Configuration();
    conf.setInt(ConfigOptions.DEFAULT_REPLICATION_FACTOR, 3);

    // Set the maximum allowed time lag for replicas to 3 seconds
    // Replicas lagging beyond this duration may be considered out of sync
    conf.set(ConfigOptions.LOG_REPLICA_MAX_LAG_TIME, Duration.ofSeconds(3));

    // Set the minimum number of in-sync replicas required to 2
    // If fewer than 2 replicas are in sync, log production requests will fail
    // and the leader's high watermark will not advance
    conf.setInt(ConfigOptions.LOG_REPLICA_MIN_IN_SYNC_REPLICAS_NUMBER, 2);
    return conf;
}
