/**
 * Sends an authentication error response to the client
 * This method constructs an error message and sends it as a JSON response with appropriate HTTP status code.
 * 
 * @param message The error message to be included in the response
 * @param response The HttpServletResponse object to send the error through
 * @throws IOException If an error occurs while writing to the response
 */
private void sendError(String message, HttpServletResponse response) throws IOException {
    // Create an error message object with forbidden status, authentication error code, and the provided message
    final ErrorMessage error = new ErrorMessage(
        HttpStatus.FORBIDDEN.value(),
        ErrorCode.AUTHENTICATION_ERROR,
        message
    );

    // Set response properties and write the error as JSON to the response output
    response.setContentType("application/json");
    response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
    response.getWriter().write(objectMapper.writeValueAsString(error));
}
