/**
 * Installs the agent on the provided instrumentation instance.
 * This method configures the agent builder with all registered handlers and installs
 * the resulting transformer on the instrumentation.
 *
 * @param instrumentation The instrumentation instance to install the agent on
 * @return A Resetter that can be used to reset the installed transformer
 */
@Override
public Resetter install(Instrumentation instrumentation) {
    // Create a default agent builder with class format changes disabled to minimize overhead
    AgentBuilder agentBuilder = new AgentBuilder.Default().disableClassFormatChanges();

    // Apply each registered handler to configure the agent builder
    // This allows for modular configuration of the agent's behavior
    for (BuilderHandler handler : handlers) {
        agentBuilder = handler.configure(agentBuilder, instrumentation);
    }

    // Install the configured transformer on the instrumentation and create a resetter
    // that can be used to remove the transformer if needed
    ResettableClassFileTransformer transformer = agentBuilder.installOn(instrumentation);
    return new TransformerResetter(transformer, instrumentation);
}
