/**
 * Attempts to acquire a specified number of permits from the rate limiter.
 * This method overrides the parent class implementation to track the number of
 * active requests by incrementing a counter before acquisition and decrementing it
 * after completion, regardless of whether the acquisition was successful.
 *
 * @param permits The number of permits to acquire
 * @param nowMicros The current time in microseconds
 * @param timeoutMicros The maximum time to wait for the permits in microseconds
 * @return true if the permits were acquired, false otherwise
 */
@Override
protected boolean doAcquire(int permits, long nowMicros, long timeoutMicros) {
    // Increment request counter before attempting to acquire permits
    requests.incrementAndGet();
    try {
        // Delegate to parent implementation for actual permit acquisition
        return super.doAcquire(permits, nowMicros, timeoutMicros);
    } finally {
        // Ensure request counter is decremented regardless of acquisition outcome
        requests.decrementAndGet();
    }
}
