/**
 * Deletes role path associations by specified path IDs
 * 
 * This method removes role path mappings for a specific role and client
 * based on the provided list of path IDs. If the list is empty, no action is taken.
 * 
 * @param roleId The ID of the role whose path associations should be deleted
 * @param clientCode The client code identifier for which the paths should be removed
 * @param pathIds List of path IDs to be deleted from the role's permissions
 */
public void deleteByPathIds(Long roleId, String clientCode, List<Long> pathIds) {
    // Skip processing if the path ID list is empty
    if (pathIds.isEmpty()){
        return;
    }

    // Execute a delete operation using lambda update to remove role path associations
    // that match the specified role ID, client code, and are in the provided path ID list
    lambdaUpdate()
            .eq(RolePath::getRoleId, roleId)
            .eq(RolePath::getClientCode, clientCode)
            .in(RolePath::getPathId, pathIds)
            .remove();
}
