/**
 * Parses a string representation of an SPG type identifier into an SPGTypeIdentifier object.
 * The string format should be either "typeName" or "namespace.typeName" where the dot
 * separates the namespace from the type name.
 *
 * @param uniqueName The string to parse, in format "typeName" or "namespace.typeName"
 * @return A new SPGTypeIdentifier instance representing the parsed components
 * @throws IllegalArgumentException If the input string doesn't match the expected format
 */
public static SPGTypeIdentifier parse(String uniqueName) {
    // Split the input string by dot and create an appropriate SPGTypeIdentifier based on components
    String[] splits = uniqueName.trim().split("\\.");
    if (splits.length == 1) {
      return new SPGTypeIdentifier(null, splits[0]);
    } else if (splits.length == 2) {
      return new SPGTypeIdentifier(splits[0], splits[1]);
    } else {
      throw new IllegalArgumentException("invalid uniqueName: " + uniqueName);
    }
  }
