/**
 * Handles the failure of a transfer order.
 * This method updates the transfer order with error information, closes it,
 * and registers a notification to the merchant about the failed transfer.
 *
 * @param transferOrder The transfer order that has failed and needs to be processed
 */
private void fail(TransferOrder transferOrder) {
    // Retrieve callback information from the current payment context
    // and update the transfer order with error details
    CallbackLocal callbackInfo = PaymentContextLocal.get().getCallbackInfo();
    transferOrder.setErrorMsg(callbackInfo.getTradeErrorMsg());

    // Close the transfer order with the finish time from callback info
    transferAssistService.close(transferOrder, callbackInfo.getFinishTime());

    // Register a notification to inform the merchant about the failed transfer
    merchantNoticeService.registerTransferNotice(transferOrder);
}
