/**
 * Starts the shell of the file system if it exists and has not already been started.
 * This method ensures the file system's shell is properly initialized when needed.
 * 
 * @throws Exception If an error occurs during the shell startup process
 */
private void startIfNeeded() throws Exception {
    // Skip if the file system is not initialized
    if (fileSystem == null) {
        return;
    }

    // Start the shell if it exists
    var s = fileSystem.getShell();
    if (s.isPresent()) {
        s.get().start();
    }
}
