/**
 * Updates the hash calculation by processing the internal buffer in block-sized chunks.
 * This method takes the accumulated data in the buffer and processes it through the hash
 * function in fixed-size blocks, then resets the buffer offset for new data.
 */
private void doUpdate() {
    // Process the buffer in BLOCK_LENGTH-sized chunks
    // Create a temporary block to hold each chunk for hashing
    byte[] B = new byte[BLOCK_LENGTH];
    for (int i = 0; i < BUFFER_LENGTH; i += BLOCK_LENGTH) {
        // Copy a block-sized chunk from the buffer to the temporary array
        System.arraycopy(xBuf, i, B, 0, B.length);
        // Process the block through the hash function
        doHash(B);
    }
    // Reset buffer offset after processing all blocks
    xBufOff = 0;
}
