/**
 * Executes the AccessMatrixAnalyzer for all non-hybrid accounts
 * 
 * This method runs the matrix analyzer for each non-hybrid account in the system.
 * The analyzer evaluates access permissions and generates matrices for analysis.
 * Any exceptions during execution are logged but don't interrupt the overall process.
 */
public void run() {
    // Execute the matrix analyzer task for all non-hybrid accounts
    // This processes each account individually and handles any exceptions that occur
    AccountTask.instance.executeTaskForNonHybridAccounts(account -> {
        AccessMatrixAnalyzer matrixAnalyzer = new AccessMatrixAnalyzer();
        try {
