 * in the application.
 *
 * @param id The ObjectId of the document to be updated
 * @param value The boolean value to set for the 'show' field (true for visible, false for hidden)
 */
public void toggleShow(ObjectId id, boolean value) {
    // Update the document's visibility status in the MongoDB collection
    // by finding the document with the specified ID and setting its 'show' field
    // to the provided boolean value without creating a new document if not found
    instance.getMCollection().findOneAndUpdate(
            Filters.eq("_id", id),
            Updates.set(Loader.SHOW, value),
            new FindOneAndUpdateOptions().upsert(false)
    );
}
