/**
 * Determines whether a follower replica can be added to the In-Sync Replicas (ISR) set.
 * A follower is eligible to be added to the ISR if:
 * 1. There's no ISR update currently in progress
 * 2. The follower is not already in the ISR
 * 3. The follower meets the eligibility criteria for ISR membership
 *
 * @param followerId The ID of the follower replica to check
 * @return true if the follower can be added to the ISR, false otherwise
 */
private boolean canAddFollowerReplicaToIsr(int followerId) {
    // Get the current ISR state and check all conditions that must be met
    // before a follower can be added to the ISR
    IsrState currentIsrState = isrState;
    return !currentIsrState.isInflight()
            && !currentIsrState.isr().contains(followerId)
            && isReplicaIsrEligible(followerId);
}
