/**
 * Decodes a UTF-8 encoded byte array to a String.
 * This method attempts to decode the input using a strict UTF-8 decoder first.
 * If strict decoding fails, it falls back to a default UTF-8 decoder.
 *
 * @param input The byte array containing UTF-8 encoded data
 * @param offset The starting position in the input array
 * @param byteLen The number of bytes to decode
 * @return A String containing the decoded characters
 */
public static String decodeUTF8(byte[] input, int offset, int byteLen) {
    // Allocate or reuse a character array of appropriate size for the decoded result
    char[] chars = allocateReuseChars(byteLen);

    // Attempt strict UTF-8 decoding first
    int len = decodeUTF8Strict(input, offset, byteLen, chars);
    if (len < 0) {
        // If strict decoding fails (indicated by negative return value),
        // fall back to the default UTF-8 decoder
        return defaultDecodeUTF8(input, offset, byteLen);
    }

    // Return a new String created from the successfully decoded characters
    return new String(chars, 0, len);
}
