/**
 * Retrieves a TypeElement for the given type name.
 * 
 * This method attempts to find a type element by its fully qualified name. If not found
 * using the original format, it tries again by replacing dollar signs with dots, which
 * handles inner class notation differences.
 *
 * @param typeName The fully qualified name of the type to retrieve
 * @return The TypeElement representing the specified type
 * @throws NullPointerException If the type cannot be found after both attempts
 */
TypeElement getTypeElement(String typeName) {
    // First attempt to get the type element using the original name
    var elem = env.getElementUtils().getTypeElement(typeName);

    // If not found, try again by replacing dollar signs with dots to handle inner classes
    if (elem == null) {
      elem = env.getElementUtils().getTypeElement(typeName.replace('$', '.'));
    }

    // Ensure the type was found and return it, otherwise throw a NullPointerException
    return requireNonNull(elem, "Could not find type '" + typeName + "'");
}
