/**
 * Polls a batch of scan records from the snapshot scanner.
 * 
 * This method attempts to retrieve a batch of records from the snapshot scanner
 * within the configured timeout period. If the scanner has reached the end of data,
 * or if no records are available within the timeout, null is returned.
 * 
 * @return An iterator containing a batch of scan records, or null if no records
 *         are available or the scanner has reached the end
 */
private Iterator<ScanRecord> pollBatch() {
    // Check if scanner has reached the end of data
    if (snapshotScanner.reachedEnd()) {
        return null;
    }

    // Poll for records with the configured timeout
    Iterator<ScanRecord> records = snapshotScanner.poll(POLL_TIMEOUT);
    return records == null ? null : new ScanRecordBatch(records);
}
