/**
 * Converts an existing collection to a capped collection with the specified size limit.
 * A capped collection is a fixed-size collection that automatically overwrites its oldest entries
 * when it reaches its maximum size.
 *
 * @param sizeInBytes The maximum size of the capped collection in bytes
 * @return Document containing the result of the conversion operation, or null if the collection doesn't exist
 */
public Document convertToCappedCollection(long sizeInBytes) {
    // Get database reference from the first client in the pool
    MongoDatabase mongoDatabase = clients[0].getDatabase(getDBName());

    // Check if the collection exists before attempting conversion
    for (Document collection: mongoDatabase.listCollections()) {
        if (collection.getString("name").equals(getCollName())) {
            // Execute the convertToCapped command with the specified size parameter
            return mongoDatabase.runCommand(new Document("convertToCapped", getCollName())
                    .append("size", sizeInBytes));
        }
    }

    // Return null if the collection doesn't exist
    return null;
}
