/**
 * Encodes a byte array into a hexadecimal character array.
 * 
 * This method converts each byte in the input array to two hexadecimal characters
 * using the provided digit character set. The high 4 bits and low 4 bits of each byte
 * are encoded separately as hexadecimal characters.
 *
 * @param data     The byte array to be encoded
 * @param toDigits The character array containing the hexadecimal digit characters
 * @return A character array containing the hexadecimal representation of the input data
 */
protected static char[] encodeHex(byte[] data, char[] toDigits) {
    int l = data.length;
    // Output array size is twice the input size since each byte becomes two hex characters
    char[] out = new char[l << 1];

    // Convert each byte to two hexadecimal characters
    for (int i = 0, j = 0; i < l; i++) {
        // Extract and convert high 4 bits (0xF0) to a hex character
        out[j++] = toDigits[(0xF0 & data[i]) >>> 4];
        // Extract and convert low 4 bits (0x0F) to a hex character
        out[j++] = toDigits[0x0F & data[i]];
    }
    return out;
}
