/**
 * Normalizes a command input string by converting the command portion to lowercase.
 * If a command contains arguments (separated by the argument separator character),
 * only the command portion (before the first separator) is converted to lowercase
 * while preserving the case of the arguments.
 *
 * @param input The command input string to normalize
 * @param trim Whether to trim whitespace from the input string
 * @return The normalized command string with command portion in lowercase
 */
static String normalizeInput(final String input, final boolean trim) {
    // Apply optional trimming based on the trim parameter
    final String command = trim ? input.trim() : input;

    // Find the first argument separator character to identify where the command name ends
    int firstSep = command.indexOf(CommandDispatcher.ARGUMENT_SEPARATOR_CHAR);
    if (firstSep != -1) {
      // If separator exists, convert only the command portion to lowercase
      // and keep the arguments portion with its original case
      return command.substring(0, firstSep).toLowerCase(Locale.ENGLISH)
          + command.substring(firstSep);
    } else {
      // If no separator exists, the entire string is the command name
      // and should be converted to lowercase
      return command.toLowerCase(Locale.ENGLISH);
    }
  }
