/**
 * Calculates the geographic distance between two geometries.
 * This method finds the nearest points between the two geometries and then
 * computes the distance between those points using the GeoUtils distance formula.
 *
 * @param fromGeometry The source geometry
 * @param toGeometry The target geometry
 * @return The distance between the nearest points of the two geometries
 */
public static double distance(Geometry fromGeometry, Geometry toGeometry) {
    // Find the nearest points between the two geometries using JTS DistanceOp
    DistanceOp distanceOp = new DistanceOp(fromGeometry, toGeometry);
    Coordinate[] coordinates = distanceOp.nearestPoints();

    // Calculate the actual distance between the nearest points
    // Note: coordinates are in (x,y) format but passed as (lat,lon) to GeoUtils
    return GeoUtils.distance(
        coordinates[0].y, coordinates[0].x, coordinates[1].y, coordinates[1].x);
}
