 * This method recursively removes all leading slashes and a single trailing slash
 * from the provided string, ensuring a consistent format for path handling.
 * 
 * @param location The string path or location to process
 * @return The location string without any leading or trailing slashes
 */
private static String stripLeadingTrailingSlash(String location) {
    // Recursively remove any leading slashes
    if (location.startsWith("/")) {
      return stripLeadingTrailingSlash(location.substring(1));
    }

    // Remove a trailing slash if present
    if (location.endsWith("/")) {
      return location.substring(0, location.length() - 1);
    } else {
