/**
 * Creates a default request object for a given beacon interface using reflection.
 * This method dynamically instantiates a request object by accessing the builder pattern
 * methods of the request class associated with the provided beacon interface.
 *
 * @param <REQ> The type of request object to create
 * @param beaconInterface The beacon interface containing information about the request class
 * @return A new instance of the request object with default values
 */
@SneakyThrows
@SuppressWarnings("unchecked")
private <REQ> REQ createDefaultRequest(BeaconInterface<?> beaconInterface) {
    // Use reflection to access the static builder method of the request class
    var c = beaconInterface.getRequestClass().getDeclaredMethod("builder");
    c.setAccessible(true);
    var b = c.invoke(null);

    // Invoke the build method on the builder instance to create the request object
    var m = b.getClass().getDeclaredMethod("build");
    m.setAccessible(true);
    return (REQ) beaconInterface.getRequestClass().cast(m.invoke(b));
}
