/**
 * Retrieves or creates a deque of WriteBatch objects for a specific table bucket and physical table path.
 * This method ensures that write batches are properly organized by table path and bucket,
 * creating the necessary data structures if they don't already exist.
 *
 * @param tableBucket The bucket identifier for which to get or create a write batch deque
 * @param physicalTablePath The physical path of the table in the storage system
 * @return A deque of WriteBatch objects associated with the specified table bucket and path
 */
private Deque<WriteBatch> getOrCreateDeque(
            TableBucket tableBucket, PhysicalTablePath physicalTablePath) {
    // First get or create the BucketAndWriteBatches object for this physical table path
    // This maintains all write batches for different buckets within the same table
    BucketAndWriteBatches bucketAndWriteBatches =
            writeBatches.computeIfAbsent(physicalTablePath, k -> new BucketAndWriteBatches());

    // Then get or create the deque of write batches for the specific bucket within the table
    // Each bucket has its own queue of write operations
    return bucketAndWriteBatches.batches.computeIfAbsent(
            tableBucket.getBucket(), k -> new ArrayDeque<>());
}
