/**
 * Determines if this storage location is a child of the specified potential parent location.
 * A location is considered a child if its path starts with the parent's path.
 * 
 * @param potentialParent The storage location to check as a potential parent
 * @return true if this location is a child of the potential parent, false otherwise
 */
public boolean isChildOf(StorageLocation potentialParent) {
    // First check if either location is null, in which case there can't be a parent-child relationship
    if (this.location == null || potentialParent.location == null) {
      return false;
    } else {
      // Normalize both locations by ensuring they end with a slash to properly compare paths
      // This prevents false positives like "/folder1" being considered a child of "/folder"
      String slashTerminatedLocation = ensureTrailingSlash(this.location);
      String slashTerminatedParentLocation = ensureTrailingSlash(potentialParent.location);
      return slashTerminatedLocation.startsWith(slashTerminatedParentLocation);
    }
  }
