/**
 * Calculates the total size in bytes required to store a key-value pair without including the size of the length field.
 * 
 * This method computes the combined size of:
 * 1. The variable-length integer representing the key length
 * 2. The key itself
 * 3. The value (row) if present
 *
 * @param key The byte array representing the key
 * @param row The optional InternalRow representing the value, can be null
 * @return The total size in bytes required for storing the key-value pair without the length field
 */
private static int sizeWithoutLength(byte[] key, @Nullable InternalRow row) {
    // Calculate total size by summing:
    // - Size of the variable-length integer encoding of the key length
    // - Size of the key itself
    // - Size of the row (if present), otherwise 0
    return VarLengthUtils.sizeOfUnsignedVarInt(key.length)
            + key.length
            + (row == null ? 0 : ((MemoryAwareGetters) row).getSizeInBytes());
}
