/**
 * Deletes a merchant application by its ID
 * This method checks if the application exists and if it has any associated channel configurations
 * before performing the deletion.
 * 
 * @param id The ID of the merchant application to delete
 * @throws ConfigNotExistException If the merchant application with the given ID does not exist
 * @throws OperationFailException If the merchant application has associated channel configurations
 */
public void delete(Long id) {
    // Find the merchant application by ID or throw exception if not found
    MchApp mchApp = mchAppManager.findById(id)
            .orElseThrow(ConfigNotExistException::new);

    // Check if the application has any associated channel configurations
    // If so, prevent deletion and throw an exception requiring the user to delete those first
    if (channelConfigManager.existedByField(ChannelConfig::getAppId, mchApp.getAppId())){
        throw new OperationFailException("该商户应用已绑定支付配置，请先删除支付配置");
    }

    // Proceed with deletion if all checks pass
    mchAppManager.deleteById(id);
}
