/**
 * Constructs a detailed error message for a failed Dubbo RPC call.
 * 
 * This method formats an error message containing information about the failed request,
 * including the interface name, method name, remote server address, and the exception
 * details. This provides comprehensive context for debugging RPC failures.
 *
 * @param throwable The exception that caused the failure
 * @param request The Dubbo outbound request that failed
 * @param endpoint The Dubbo endpoint that was the target of the request
 * @return A formatted error message string with detailed context about the failed call
 */
@Override
protected String getError(Throwable throwable, DubboOutboundRequest request, DubboEndpoint<?> endpoint) {
    // If the endpoint is null, simply return the exception message
    if (endpoint == null) {
        return throwable.getMessage();
    }

    // Extract request details and construct a comprehensive error message containing
    // the interface name, method name, remote server address, and exception details
    Invocation invocation = request.getRequest();
    return "Failed to call " + invocation.getInvoker().getInterface().getName() + "." + invocation.getMethodName()
            + " on remote server: " + endpoint.getInvoker().getUrl().getAddress() + ", cause by: "
            + throwable.getClass().getName() + ", message is: " + throwable.getMessage();
}
