/**
 * Expands the internal arrays to accommodate more data.
 * This method increases the capacity of the base and check arrays by 65535 elements
 * to prevent frequent reallocations when the trie grows.
 */
private void loseWeight() {
    // Expand the base array by creating a new larger array and copying existing data
    int[] nbase = new int[size + 65535];
    System.arraycopy(base, 0, nbase, 0, size);
    base = nbase;

    // Expand the check array similarly, ensuring we don't copy beyond the bounds of either array
    int[] ncheck = new int[size + 65535];
    System.arraycopy(check, 0, ncheck, 0, Math.min(check.length, ncheck.length));
    check = ncheck;
}
