 * The unique name should be in the format "namespace.name" or simply "name".
 * 
 * @param uniqueName The string to parse, which can be either a simple name or namespace-qualified name
 * @return A new SPGTypeIdentifier constructed from the parsed components
 * @throws IllegalArgumentException If the uniqueName format is invalid (contains more than one dot)
 */
public static SPGTypeIdentifier parse(String uniqueName) {
    // Split the unique name by dots and create appropriate SPGTypeIdentifier based on components
    // For a simple name (no dots), namespace is null
    // For namespace.name format, parse both components
    // Reject inputs with more than one dot as invalid
    String[] splits = uniqueName.trim().split("\\.");
    if (splits.length == 1) {
      return new SPGTypeIdentifier(null, splits[0]);
    } else if (splits.length == 2) {
