/**
 * Converts a multi-valued map to a single-valued map.
 * 
 * This method creates a new LinkedHashMap containing only the first value
 * for each key in the original multi-valued map. If a key has no values
 * or null values, it will be excluded from the result.
 * 
 * @return A new Map containing only the first value for each key
 */
@Override
public Map<K, V> toSingleValueMap() {
    // Create a new LinkedHashMap with the same size as the delegate map
    Map<K, V> singleValueMap = newLinkedHashMap(delegate.size());

    // For each key-value pair in the delegate map, extract only the first value
    // and add it to the single value map if the values list is not empty
    delegate.forEach((key, values) -> {
        if (values != null && !values.isEmpty()) {
            singleValueMap.put(key, values.get(0));
        }
    });

    return singleValueMap;
}
