/**
 * Retrieves the next scan record from the collection of iterators.
 * This method iterates through multiple collections until it finds a non-empty iterator
 * with available elements, then returns the next element from that iterator.
 * 
 * @return The next available ScanRecord from any of the iterators
 *         or signals completion if all iterators are exhausted
 */
public ScanRecord makeNext() {
    // Find the next non-empty iterator by advancing through the collection of iterators
    // until we find one with remaining elements or exhaust all iterators
    while (current == null || !current.hasNext()) {
        if (iters.hasNext()) {
            current = iters.next().iterator();
        } else {
            return allDone(); // All iterators exhausted, signal completion
        }
    }

    // Return the next element from the current iterator
    return current.next();
}
