/**
 * Determines the installation path for Microsoft Visual Studio Code on Windows.
 * This method looks for the VS Code executable (code.cmd) in the standard Windows
 * installation directory under the Local AppData folder.
 * 
 * @return An Optional containing the path to the VS Code executable if the standard
 *         installation location is used
 */
@Override
protected Optional<Path> determineInstallation() {
    // Construct the path to VS Code's executable by starting from the LOCALAPPDATA
    // environment variable and appending the standard installation subdirectories
    return Optional.of(Path.of(System.getenv("LOCALAPPDATA"))
            .resolve("Programs")
            .resolve("Microsoft VS Code")
            .resolve("bin")
            .resolve("code.cmd"));
}
