/**
 * Creates a single-threaded executor service for DNS lookup operations.
 * 
 * This method initializes a fixed thread pool with exactly one thread to handle
 * DNS lookup tasks. Using a single thread simplifies the implementation while
 * still providing asynchronous operation capabilities.
 * 
 * @return A single-threaded ExecutorService with custom thread factory
 */
private ExecutorService createThreadPool() {
    // Create a fixed thread pool with a single thread for DNS lookups
    // Using a single thread simplifies the implementation while maintaining
    // asynchronous capabilities without the complexity of multiple threads
    return Executors.newFixedThreadPool(1, new ExecutorThreadFactory(LOOKUP_THREAD_PREFIX));
}
