/**
 * Retrieves an API key by its ID for a specific user
 * 
 * This method fetches an API key from the repository and verifies that it belongs
 * to the specified user before returning it. If the API key doesn't exist or
 * doesn't belong to the user, a ResourceNotFoundException is thrown.
 *
 * @param user The user requesting the API key
 * @param id The ID of the API key to retrieve
 * @return The requested API key if found and owned by the user
 * @throws ResourceNotFoundException If the API key doesn't exist or doesn't belong to the user
 */
public ApiKey get(User user, Long id) {
    // Retrieve the API key from repository or throw exception if not found
    final ApiKey toReturn = repository.findById(id).orElseThrow(() -> new ResourceNotFoundException(id));

    // Verify that the API key belongs to the requesting user
    if (!toReturn.getUser().equals(user)) {
        throw new ResourceNotFoundException(id);
    }

    return toReturn;
}
