/**
 * Creates the base structure for a dialog component.
 * This method constructs the dialog's layout by combining content and navigation elements
 * into a vertically arranged structure with proper styling and growth behavior.
 * 
 * @return A component structure containing the fully assembled dialog layout
 */
@Override
public CompStructure<Region> createBase() {
    // Create the main content pane with appropriate styling
    var sp = pane(content()).styleClass("dialog-content").createRegion();

    // Build the vertical container and add content and navigation components
    VBox vbox = new VBox();
    vbox.getChildren().addAll(sp, createNavigation());
    vbox.getStyleClass().add("dialog-comp");
    vbox.setFillWidth(true);
    VBox.setVgrow(sp, Priority.ALWAYS);

    return new SimpleCompStructure<>(vbox);
}
