/**
 * Parses the remaining text in the StringReader into an array of strings.
 * This method splits the text using a predefined word splitter pattern and
 * advances the reader cursor to the end.
 *
 * @param reader The StringReader containing the text to parse
 * @return An array of strings resulting from splitting the input text
 * @throws CommandSyntaxException If an error occurs during parsing
 */
@Override
public String[] parse(final StringReader reader) throws CommandSyntaxException {
    // Extract all remaining text from the reader and advance cursor to the end
    final String text = reader.getRemaining();
    reader.setCursor(reader.getTotalLength());

    // Return empty array if there's no text to parse
    if (text.isEmpty()) {
      return EMPTY;
    }

    // Split the text using the predefined word splitter and convert to array
    return WORD_SPLITTER.splitToList(text).toArray(EMPTY);
}
