/**
 * Converts a string from PascalCase or camelCase to snake_case format.
 * This method identifies words in the input string using a pattern matcher
 * and joins them with underscores to create a snake_case representation.
 *
 * @param name The string in PascalCase or camelCase to be converted
 * @return The converted string in snake_case format
 */
public static String toSnakeCase(String name) {
    // Build the snake_case string by finding words in the input and joining them with underscores
    StringBuilder sb = new StringBuilder();
    Matcher matcher = PASCAL_WORD_PATTERN.matcher(name);
    while (matcher.find()) {
      if (sb.length() > 0) sb.append('_');
      sb.append(matcher.group().toLowerCase());
    }
    return sb.toString();
}
