/**
 * Selects a specific settings category by its ID.
 * This method navigates to the settings section of the application layout
 * and selects the specified category if it exists.
 * 
 * @param id The unique identifier of the category to select
 */
public void selectCategory(String id) {
    // Navigate to the settings section in the application layout
    AppLayoutModel.get().selectSettings();

    // Search for the category with the matching ID in the categories collection
    var found = categories.stream()
            .filter(appPrefsCategory -> appPrefsCategory.getId().equals(id))
            .findFirst();

    // If the category is found, update the selected category value
    found.ifPresent(appPrefsCategory -> {
        selectedCategory.setValue(appPrefsCategory);
    });
}
