/**
 * Filters and returns a list of selectable preference choice values of the specified type.
 * 
 * This method retrieves all available preference choice values of the given type
 * and filters out those that are not selectable according to their implementation.
 *
 * @param <T> The type of preference choice values to retrieve
 * @param type The class object representing the type of preference choice values
 * @return A filtered list containing only the selectable preference choice values
 * @throws AssertionError If no preference choice values of the specified type are found
 */
static <T> List<T> getSupported(Class<T> type) {
    // Get all preference choice values of the specified type and verify they exist
    var all = getAll(type);
    if (all == null) {
        throw new AssertionError();
    }

    // Filter the list to include only selectable items and return as an immutable list
    return all.stream().filter(t -> ((PrefsChoiceValue) t).isSelectable()).toList();
}
