/**
 * Retrieves the upper-level concept for a given concept in a hierarchy.
 * This method finds the parent/upper concept by retrieving outgoing edges 
 * from the specified concept vertex.
 *
 * @param conceptType The type of the concept to find the upper level for
 * @param concept The concept identifier for which to find the upper level
 * @return The identifier of the upper-level concept, or null if none exists
 */
@Override
public String getUpper(String conceptType, String concept) {
    // Create a vertex ID from the concept and its type
    IVertexId id = IVertexId.from(concept, conceptType);

    // Retrieve all outgoing edges of the specified edge types from this concept
    List<IEdge<IVertexId, IProperty>> edgeList =
        this.getEdges(id, null, null, getEdgeTypeSet(conceptType), Direction.OUT);

    // If no edges exist, there is no upper concept
    if (CollectionUtils.isEmpty(edgeList)) {
      return null;
    }

    // Return the target ID from the first edge, which represents the upper concept
    return (String) edgeList.get(0).getValue().get(Constants.EDGE_TO_ID_KEY);
}
