/**
 * Saves the original reconciliation file to storage and returns its URL
 * This method formats a filename based on the reconciliation date, uploads the file bytes
 * to the file storage service, and returns the resulting URL.
 *
 * @param reconcileOrder The reconciliation statement containing date information
 * @param bytes The file content as byte array to be saved
 * @return The URL of the saved file
 */
private String saveOriginalFile(ReconcileStatement reconcileOrder, byte[] bytes) {
    // Format the filename using the reconciliation date in pure date format (e.g., 20230101)
    String date = LocalDateTimeUtil.format(reconcileOrder.getDate(), DatePattern.PURE_DATE_PATTERN);
    String fileName = StrUtil.format("交易对账单-微信-{}.csv", date);

    // Prepare the file for upload and set the original filename
    var uploadPretreatment = fileStorageService.of(bytes);
    if (StrUtil.isNotBlank(fileName)) {
        uploadPretreatment.setOriginalFilename(fileName);
    }

    // Upload the file and return its URL
    FileInfo upload = uploadPretreatment.upload();
    return upload.getUrl();
}
