/**
 * Registers metrics related to Java ClassLoader activity with the provided metrics group.
 * 
 * This method creates gauges that track the total number of loaded and unloaded classes
 * by accessing the JVM's ClassLoadingMXBean through JMX.
 *
 * @param metrics The MetricGroup where ClassLoader metrics should be registered
 */
private static void instantiateClassLoaderMetrics(MetricGroup metrics) {
    // Access the JVM's ClassLoading management bean and register gauges for
    // tracking both loaded and unloaded class counts
    final ClassLoadingMXBean mxBean = ManagementFactory.getClassLoadingMXBean();
    metrics.<Long, Gauge<Long>>gauge("classesLoaded", mxBean::getTotalLoadedClassCount);
    metrics.<Long, Gauge<Long>>gauge("classesUnloaded", mxBean::getUnloadedClassCount);
}
