 * @return A map containing the edge context with the specified alias as the key
 */
public static Map<String, Object> edgeContext(
      IEdge<IVertexId, IProperty> edge, SPO spo, String alias) {
    // If no SPO is provided, create a new one based on the edge type
    if (null == spo) {
      spo = new SPO(edge.getType());
    }

    // Create the result map and populate it with the edge context using the specified alias
    Map<String, Object> result = new HashMap<>();
    result.put(alias, edgeContext(edge, spo.getP(), null));
    return result;
