/**
 * Checks if the number of proxies stripped exceeds a safety threshold to prevent infinite loops.
 * 
 * This method serves as a safety mechanism to detect potential circular references in the object graph
 * during proxy stripping operations. If the number of proxies stripped reaches or exceeds the maximum
 * allowed iterations defined by SAFETY_NET_MAX_ITERATIONS, an IllegalArgumentException is thrown.
 * 
 * @param numProxiesStripped The current count of proxies that have been stripped
 * @throws IllegalArgumentException If the safety threshold has been reached or exceeded
 */
private static void throwIfSafetyNetExceeded(final int numProxiesStripped) {
    // Check if we've exceeded the maximum allowed proxy stripping iterations
    // and throw an exception if a potential infinite loop is detected
    if (numProxiesStripped >= SAFETY_NET_MAX_ITERATIONS) {
        throw new IllegalArgumentException(
                format(
                        "Already stripped %d proxies. "
                                + "Are there loops in the object graph?",
                        SAFETY_NET_MAX_ITERATIONS));
    }
}
