/**
 * Filters outbound requests by excluding endpoints that have already been attempted.
 * 
 * This method examines the request's attempt history and filters out any endpoints
 * that have been previously tried, ensuring that requests are only routed to 
 * endpoints that haven't been attempted yet.
 *
 * @param <T> The type of outbound request being processed
 * @param invocation The outbound invocation containing the request and route information
 * @param chain The filter chain to continue processing after this filter completes
 */
@Override
public <T extends OutboundRequest> void filter(OutboundInvocation<T> invocation, RouteFilterChain chain) {
    // Get the route target and the set of previously attempted endpoint IDs
    RouteTarget target = invocation.getRouteTarget();
    Set<String> attempts = invocation.getRequest().getAttempts();

    // If there are previous attempts, filter out those endpoints from the target
    // to prevent routing to endpoints that have already been tried
    if (attempts != null && !attempts.isEmpty()) {
        target.filter(endpoint -> !attempts.contains(endpoint.getId()), -1, false);
    }

    // Continue with the filter chain processing
    chain.filter(invocation);
}
