 * This method temporarily changes the current thread's context ClassLoader and returns
 * a context object that can be used to restore the original ClassLoader when done.
 *
 * @param cl The ClassLoader to be set as the current thread's context ClassLoader
 * @return A TemporaryClassLoaderContext instance that manages the ClassLoader change
 */
public static TemporaryClassLoaderContext of(ClassLoader cl) {
    // Get the current thread and save its original ClassLoader
    final Thread t = Thread.currentThread();
    final ClassLoader original = t.getContextClassLoader();

    // Set the new ClassLoader as the thread's context ClassLoader
    t.setContextClassLoader(cl);

    // Return a new context object that will allow restoring the original ClassLoader
    return new TemporaryClassLoaderContext(t, original);
