 * This method tracks and updates the state information for a writer when appending
 * a batch of log records. It either retrieves existing writer append information
 * or creates new information if this is the first batch from this writer.
 * 
 * @param writerStateManager The manager responsible for tracking writer states
 * @param batch The batch of log records to be appended
 * @param writers A map of writer IDs to their corresponding append information
 */
private static void updateWriterAppendInfo(
            WriterStateManager writerStateManager,
            LogRecordBatch batch,
            Map<Long, WriterAppendInfo> writers) {
        // Get or create writer append info for this batch's writer ID
        // If this is the first time seeing this writer ID, prepare a new state update
        long writerId = batch.writerId();
        WriterAppendInfo appendInfo =
                writers.computeIfAbsent(writerId, id -> writerStateManager.prepareUpdate(writerId));

        // Update the append info with the current batch
        appendInfo.append(batch);
