/**
 * Creates a MongoDB filter (Bson) for querying API information based on collection type and API key.
 * This method constructs a compound filter that matches documents by URL, HTTP method, and collection IDs.
 * 
 * @param type The collection type that determines the field prefix in the database
 * @param api The API key information containing URL, method, and collection ID to filter by
 * @return A Bson filter that can be used in MongoDB queries to find matching API documents
 */
private static Bson createApiFilters(CollectionType type, ApiInfoKey api) {
    // Get the appropriate field prefix based on the collection type
    // This handles different document structures in various collection types
    String prefix = getFilterPrefix(type);

    // Create a compound filter with three conditions:
    // 1. URL must match exactly
    // 2. HTTP method must match exactly
    // 3. The document's collection IDs must contain the API's collection ID
    return Filters.and(
            Filters.eq(prefix + SingleTypeInfo._URL, api.getUrl()),
            Filters.eq(prefix + SingleTypeInfo._METHOD, api.getMethod().toString()),
            Filters.in(SingleTypeInfo._COLLECTION_IDS, api.getApiCollectionId()));
}
