/**
 * Reads a TimestampNtz value from the input stream with the specified precision.
 * 
 * This method handles two different timestamp formats based on precision:
 * - For compact format: reads a single long value representing milliseconds
 * - For high precision format: reads milliseconds and additional nanoseconds separately
 *
 * @param precision The precision level of the timestamp to be read
 * @return A TimestampNtz object constructed from the read values
 */
public TimestampNtz readTimestampNtz(int precision) {
    // For compact timestamp format, read only milliseconds as a long value
    if (TimestampNtz.isCompact(precision)) {
        return TimestampNtz.fromMillis(readLong());
    }

    // For high precision timestamp format, read milliseconds and nanoseconds separately
    long milliseconds = readLong();
    int nanosOfMillisecond = readInt();
    return TimestampNtz.fromMillis(milliseconds, nanosOfMillisecond);
}
