/**
 * Marks a specific offset as flushed in the buffer and updates the recovery point if necessary.
 * This method is used to track the last successfully flushed position in the buffer,
 * which is important for recovery operations.
 *
 * @param offset The offset position to mark as flushed
 * @throws IllegalStateException If the memory mapped buffer has been closed
 */
void markFlushed(long offset) {
    // Ensure the buffer is still open before proceeding
    checkIfMemoryMappedBufferClosed();

    // Only update the recovery point if the new offset is greater than the current one
    if (offset > recoveryPoint) {
        updateRecoveryPoint(offset);
        lastFlushedTime.set(System.currentTimeMillis());
    }
}
