 * This method queries the database for runtime metrics between the start and end timestamps,
 * extracts the instance IDs, and stores them in the instanceIds list.
 * 
 * @return A string indicating the success status of the operation (uppercase "SUCCESS")
 */
public String fetchRuntimeInstances() {
    // Initialize list to store instance IDs and retrieve runtime metrics within the specified time range
    instanceIds = new ArrayList<>();
    Bson filters = RuntimeMetricsDao.buildFilters(startTimestamp, endTimestamp);
    runtimeMetrics = RuntimeMetricsDao.instance.findAll(filters, 0, 0, 
