/**
 * Extracts the partition path from a file path relative to the table base path.
 * 
 * This method calculates the relative path between the table base directory and
 * the directory containing the file, excluding both the table base path and the
 * filename itself. If the file is directly in the table base directory, an empty
 * string is returned.
 *
 * @param tableBasePath The base path of the table
 * @param filePath The full path to the file
 * @return The partition path as a string, or empty string if the file is directly in the base path
 */
public static String getPartitionPath(Path tableBasePath, Path filePath) {
  // Extract the filename and the full path as strings
  String fileName = filePath.getName();
  String pathStr = filePath.toUri().getPath();

  // Calculate the partition path by removing the base path prefix and the filename suffix
  int startIndex = tableBasePath.toUri().getPath().length() + 1;
  int endIndex = pathStr.length() - fileName.length() - 1;

  // Return empty string if the file is directly in the base path
  return endIndex <= startIndex ? "" : pathStr.substring(startIndex, endIndex);
}
