/**
 * Decodes player data from a ByteBuf based on the protocol version.
 * This method handles different protocol versions by reading the player ID and status
 * in the appropriate format depending on the Minecraft version.
 *
 * @param buf The ByteBuf containing the encoded data
 * @param direction The direction of the packet (client/server)
 * @param protocolVersion The Minecraft protocol version
 */
@Override
public void decode(final ByteBuf buf, final Direction direction, final ProtocolVersion protocolVersion) {
  // For newer versions (1.20.3+), read the player ID as UUID
  if (protocolVersion.noLessThan(ProtocolVersion.MINECRAFT_1_20_3)) {
    this.id = ProtocolUtils.readUuid(buf);
  }

  // For older versions (1.9.4 and below), read the hash string
  if (protocolVersion.noGreaterThan(ProtocolVersion.MINECRAFT_1_9_4)) {
