/**
 * Creates a circuit break exception when a request is rejected due to circuit breaker activation.
 * This method is called when the circuit breaker rejects a request to prevent cascading failures
 * in the system. It wraps the original exception in a NestedRuntimeException with an appropriate
 * HTTP status code.
 *
 * @param exception The original circuit breaker rejection exception
 * @param request The HTTP inbound request that was rejected
 * @return A NestedRuntimeException with SERVICE_UNAVAILABLE status code
 */
@Override
protected NestedRuntimeException createCircuitBreakException(RejectCircuitBreakException exception, HttpInboundRequest request) {
    // Create a new exception with SERVICE_UNAVAILABLE (503) status code to indicate the service is temporarily unavailable
    return createException(HttpStatus.SERVICE_UNAVAILABLE, exception.getMessage(), exception);
}
