/**
 * Validates the order before closing the payment transaction.
 * This method checks if the order is eligible for cancellation based on the payment method
 * and retrieves the WeChat Pay configuration.
 * 
 * @throws ValidationFailedException If the order does not support cancellation
 */
@Override
public void doBeforeCloseHandler() {
    // Get the current payment order
    PayOrder order = this.getOrder();

    // Validate that barcode payment method is used if cancellation is requested
    // Only barcode payments can be cancelled in WeChat Pay
    if (this.isUseCancel() && !order.getMethod().equals(PayMethodEnum.BARCODE.getCode())){
        throw new ValidationFailedException("该订单不支持撤销操作");
    }

    // Retrieve and validate the WeChat Pay configuration
    this.config = wechatPayConfigService.getAndCheckConfig(true);
}
